import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"出使德意志皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/110-出使德意志皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/110-出使德意志皇帝.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/110-出使德意志皇帝.md"};function o(s,a,n,m,d,p){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使德意志皇帝",tabindex:"-1"},[t("出使德意志皇帝 "),e("a",{class:"header-anchor",href:"#出使德意志皇帝","aria-label":'Permalink to "出使德意志皇帝"'},"​")],-1),e("p",null,"出使德意志皇帝 人，所以威尼斯人发现，如果德意志人决定开战，那么肯定免不了一场苦 斗 。德意志人对威尼斯人的战争看来无法避免，除非他们的骑兵不够，因 为他们把步兵的作用看得很小。威尼斯人大开火炮，猛烈攻击德意志人， 炸死了很多人。但是德意志人后来袭击了保卫火炮的士兵，把那些士兵打 倒，夺取了2门火炮，并毁坏了剩余的火炮。于是，威尼斯人撤营溃逃， 后退到罗韦雷多。他们直到5月20日还在罗韦雷多。 德意志人一发现威尼斯人已经撤退，就开始解散部队。从那个地方前 来的人说，现在卡利亚诺剩下的德意志步兵不超过3000人。除了布伦瑞克 公爵的骑兵已经回家之外，萨克森、纽伦堡、乌尔姆和其他拥有8到10匹 马的小领主，也都回家了。因此，现在德意志人总共只有600骑兵，比他 们之前拥有的要少得多。这些就是这里的战况。但是诸位大人必须知道， 在弗留利，威尼斯人已经攻占了戈里茨、波代诺内和的里雅斯特。总而言 之 ，攻占了那里属于皇帝的整个地区。皇帝在那里从来就没有足够的兵 力，可以真正对抗任何敌人。事实上，皇帝在那里的骑兵从来不超过400 名，步兵大概也只有4000到5000人。这些士兵是从奥地利和卡林西亚派 到那里的，他们在那里只停留了几天，然后就因为资金短缺离开了。 现在我将说明有关协商的情况，特别是士瓦本会议进行的情况。皇帝 在大斋节的第三或第四个周日召集了乌尔姆的全部长官，然后向他们说明 他需要的支持(如前所述)。这些长官必须回去向他们的居民说明情况， 然后在复活节后的第八天回到这里，向皇帝报告他们的决定。这一天已经 过去了，但是还不知道情况如何。皇帝现在何处，也不知道。有人说，皇 帝已经去科隆参加新任主教的遴选，因为原来的主教去世了。不过我不能 肯定，这个消息是否属实。有人说，皇帝去到美因茨，调解那里的大主教 和黑森领主因为边境问题而起的矛盾。有人说，皇帝去到盖尔德斯领地， 处理那里的问题。还有人说，皇帝去到加来会见英格兰国王，商议玛格丽 特公主的婚事，并且用他的珠宝抵押借钱。 保罗 · 德 · 利希滕施泰因大人提出付款的建议(此事我已经向诸位大",-1),e("p",null,"Opere complete di Niccolo Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{h as __pageData,f as default};
